import React from 'react'
import { Button, DialogOverlay, DialogOverlayActions } from '@fs/zion-ui'
import { useTranslation } from 'react-i18next'
import { setChatPreference } from '../../services/chatUserPreferenceService/chatUserPreferenceService'

export default function ChatMultiSelectDialogOverlay({
  overlay,
  titleName = 'Confirm Action',
  message = 'Are you sure you want to proceed with this action?',
  action,
  preferenceKey,
}) {
  const [t] = useTranslation()

  if (message === '') {
    return null
  }

  const handleConfirm = async () => {
    // Set preference to indicate user has seen this confirmation
    if (preferenceKey) {
      try {
        await setChatPreference(preferenceKey, true)
      } catch (error) {
        // Log error but don't prevent action from executing
        console.error(`Error setting preference ${preferenceKey}:`, error)
      }
    }

    if (action) {
      await action()
    }
    overlay.close()
  }

  return (
    <DialogOverlay
      title={titleName}
      size="sm"
      footer={
        <DialogOverlayActions>
          <Button onClick={overlay.close}>{t('common-ui:cancel.action', 'Cancel')}</Button>
          <Button onClick={handleConfirm} emphasis="high">
            {titleName}
          </Button>
        </DialogOverlayActions>
      }
      {...overlay}
    >
      {message}
    </DialogOverlay>
  )
}
