import React from 'react'
import { Button } from '@fs/zion-ui'
import { useTranslation } from 'react-i18next'
import { useChatMultiSelectDispatch, actionTypes } from '../../../providers/ChatMultiSelectProvider'

export default function ChatMultiSelectButton() {
  const [t] = useTranslation()
  const chatMultiSelectDispatch = useChatMultiSelectDispatch()

  const handleMultiSelectClick = () => {
    chatMultiSelectDispatch({
      type: actionTypes.SET_MULTI_SELECT_IS_ACTIVE,
      multiSelectIsActive: true,
    })
  }
  return (
    <Button dense onClick={handleMultiSelectClick}>
      {t('common-ui:select.action', 'Select')}
    </Button>
  )
}
