import { useCallback, useMemo } from 'react'
import { useTranslation } from 'react-i18next'
import { useStatusOverlay } from '@fs/zion-ui'
import { useChatState } from '../providers/ChatStateProvider'
import { useChatMultiSelectDispatch, useChatMultiSelectState, actionTypes } from '../providers/ChatMultiSelectProvider'
import useChatLog from './useChatLog'
import useHandleChatErrors from './useHandleChatErrors'
import { canLeaveChat } from '../helpers/stream/streamChatHelper'
import { getChildThreadChannels } from '../helpers/stream/streamChatChannelsHelper'
import { markChannelsRead, addOrRemoveChannelMembers } from './channelHooks'

export const useMultiSelectActions = () => {
  const [t] = useTranslation()
  const { channels, client, isEmbedded } = useChatState()
  const { selectedChannels } = useChatMultiSelectState()
  const multiSelectDispatch = useChatMultiSelectDispatch()
  const showStatusOverlay = useStatusOverlay()
  const { log, track } = useChatLog({ component: '[useMultiSelectActions]' })
  const { handleBasicError } = useHandleChatErrors({ log })

  const channelMap = useMemo(() => {
    return new Map(channels.map((channel) => [channel.cid, channel]))
  }, [channels])

  const getSelectedChannelObjects = useCallback(() => {
    return Array.from(selectedChannels)
      .map((cid) => channelMap.get(cid))
      .filter(Boolean)
  }, [selectedChannels, channelMap])

  // Helper function to clear selection, turn off multi-select and show success message
  const finishMultiSelectAction = useCallback(
    (count, translationKey, actionPastTense) => {
      multiSelectDispatch({ type: actionTypes.CLEAR_SELECTED_CHANNELS })
      multiSelectDispatch({ type: actionTypes.SET_MULTI_SELECT_IS_ACTIVE, multiSelectIsActive: false })

      showStatusOverlay({
        type: 'success',
        message: t(translationKey, `{count} {count, plural, one {chat was} other {chats were}} ${actionPastTense}.`, {
          count,
        }),
        dismissable: true,
        transient: true,
      })
    },
    [multiSelectDispatch, showStatusOverlay, t]
  )

  // Check if all selected channels can be left
  const canLeaveAllSelectedChannels = useCallback(() => {
    const selectedChannelObjects = getSelectedChannelObjects()
    return selectedChannelObjects.length > 0 && selectedChannelObjects.every((channel) => canLeaveChat({ channel }))
  }, [getSelectedChannelObjects])

  const hideSelectedChannels = useCallback(async () => {
    const channelsToHide = getSelectedChannelObjects()

    try {
      track({ link_name: 'Chat:Multi-Select Hide Channels' })

      // Hide all selected channels and their threads
      const hidePromises = channelsToHide.flatMap(async (channel) => {
        const childThreads = await getChildThreadChannels({ client, cid: channel?.cid, log })

        // Create promises for the main channel and all child threads
        const mainChannelPromise = channel.hide()
        const childThreadPromises = childThreads.map((threadChannel) =>
          threadChannel.hide().catch((error) => log({ msg: `Error hiding child thread ${error}` }))
        )

        return [mainChannelPromise, ...childThreadPromises]
      })

      await Promise.all(hidePromises)

      // Clear selection, turn off multi-select and show success message
      finishMultiSelectAction(channelsToHide.length, 'chat.multi-select.hide-success.message', 'hidden')
    } catch (error) {
      handleBasicError(error, {
        moreInfo: `Problem hiding multiple channels. Channel count: ${channelsToHide.length}`,
      })
    }
  }, [getSelectedChannelObjects, track, log, handleBasicError, finishMultiSelectAction, client])

  const leaveSelectedChannels = useCallback(async () => {
    const channelsToLeave = getSelectedChannelObjects()

    try {
      track({ link_name: 'Chat:Multi-Select Leave Channels' })

      // Leave all selected channels and their threads
      const leavePromises = channelsToLeave.flatMap(async (channel) => {
        const childThreads = await getChildThreadChannels({ client, cid: channel?.cid, log })

        // Create promises for the main channel and all child threads
        const mainChannelPromise = (async () => {
          // Embedded chat can continue to view a channel after leaving, and should still watch it
          if (!isEmbedded) await channel.stopWatching()
          await addOrRemoveChannelMembers({ cid: channel.cid, cisIdsToRemove: [client?.user?.fs_cis_id], log })
        })()

        const childThreadPromises = childThreads.map(async (threadChannel) => {
          try {
            await threadChannel.stopWatching()
            await addOrRemoveChannelMembers({ cid: threadChannel?.cid, cisIdsToRemove: [client?.user?.fs_cis_id], log })
          } catch (error) {
            // Only log failures to leave threads
            log({ msg: `Error leaving child thread when leaving a channel ${error}` })
          }
        })

        return [mainChannelPromise, ...childThreadPromises]
      })

      await Promise.all(leavePromises)

      // Clear selection, turn off multi-select and show success message
      finishMultiSelectAction(channelsToLeave.length, 'chat.multi-select.leave-success.message', 'left')
    } catch (error) {
      handleBasicError(error, {
        moreInfo: `Problem leaving multiple channels. Channel count: ${channelsToLeave.length}`,
      })
    }
  }, [getSelectedChannelObjects, track, log, handleBasicError, client, isEmbedded, finishMultiSelectAction])

  const markSelectedChannelsAsRead = useCallback(async () => {
    const channelsToMarkRead = getSelectedChannelObjects()

    try {
      track({ link_name: 'Chat:Multi-Select Mark Channels as Read' })

      // Mark all selected channels and their threads as read
      const channelGroups = await Promise.all(
        channelsToMarkRead.map(async (channel) => {
          const childThreads = await getChildThreadChannels({ client, cid: channel?.cid, log })
          return [channel, ...childThreads]
        })
      )
      const allChannelsToMark = channelGroups.flat()

      markChannelsRead({ channels: allChannelsToMark, handleBasicError })

      // Clear selection, turn off multi-select and show success message
      finishMultiSelectAction(
        channelsToMarkRead.length,
        'chat.multi-select.mark-read-success.message',
        'marked as read'
      )
    } catch (error) {
      handleBasicError(error, {
        moreInfo: `Problem marking multiple channels as read. Channel count: ${channelsToMarkRead.length}`,
      })
    }
  }, [getSelectedChannelObjects, track, handleBasicError, client, finishMultiSelectAction, log])

  const muteSelectedChannels = useCallback(async () => {
    const channelsToMute = getSelectedChannelObjects()

    try {
      track({ link_name: 'Chat:Multi-Select Mute Channels' })

      // Mute all selected channels and their threads
      const mutePromises = channelsToMute.flatMap(async (channel) => {
        const childThreads = await getChildThreadChannels({ client, cid: channel?.cid, log })

        // Create promises for the main channel and all child threads
        const mainChannelPromise = channel.mute()
        const childThreadPromises = childThreads.map((threadChannel) =>
          threadChannel.mute().catch((error) => log({ msg: `Error muting child thread ${error}` }))
        )

        return [mainChannelPromise, ...childThreadPromises]
      })

      await Promise.all(mutePromises)

      // Clear selection, turn off multi-select and show success message
      finishMultiSelectAction(channelsToMute.length, 'chat.multi-select.mute-success.message', 'muted')
    } catch (error) {
      handleBasicError(error, {
        moreInfo: `Problem muting multiple channels. Channel count: ${channelsToMute.length}`,
      })
    }
  }, [getSelectedChannelObjects, track, log, handleBasicError, client, finishMultiSelectAction])

  const unmuteSelectedChannels = useCallback(async () => {
    const channelsToUnmute = getSelectedChannelObjects()

    try {
      track({ link_name: 'Chat:Multi-Select Unmute Channels' })

      // Unmute all selected channels and their threads
      const unmutePromises = channelsToUnmute.flatMap(async (channel) => {
        const childThreads = await getChildThreadChannels({ client, cid: channel?.cid, log })

        // Create promises for the main channel and all child threads
        const mainChannelPromise = channel.unmute()
        const childThreadPromises = childThreads.map((threadChannel) =>
          threadChannel.unmute().catch((error) => log({ msg: `Error unmuting child thread ${error}` }))
        )

        return [mainChannelPromise, ...childThreadPromises]
      })

      await Promise.all(unmutePromises)

      // Clear selection, turn off multi-select and show success message
      finishMultiSelectAction(channelsToUnmute.length, 'chat.multi-select.unmute-success.message', 'unmuted')
    } catch (error) {
      handleBasicError(error, {
        moreInfo: `Problem unmuting multiple channels. Channel count: ${channelsToUnmute.length}`,
      })
    }
  }, [getSelectedChannelObjects, track, log, handleBasicError, client, finishMultiSelectAction])

  return {
    hideSelectedChannels,
    leaveSelectedChannels,
    markSelectedChannelsAsRead,
    muteSelectedChannels,
    unmuteSelectedChannels,
    canLeaveAllSelectedChannels,
  }
}
