import React from 'react'
import { InlineButton } from '@fs/zion-ui'
import { useTranslation } from 'react-i18next'
import { useChatMultiSelectDispatch, actionTypes } from '../../../providers/ChatMultiSelectProvider'

export default function ChatMultiSelectCancelButton() {
  const [t] = useTranslation()
  const multiSelectDispatch = useChatMultiSelectDispatch()

  const handleMultiSelectCancelClick = () => {
    multiSelectDispatch({ type: actionTypes.CLEAR_SELECTED_CHANNELS })
    multiSelectDispatch({
      type: actionTypes.SET_MULTI_SELECT_IS_ACTIVE,
      multiSelectIsActive: false,
    })
  }
  return <InlineButton onClick={handleMultiSelectCancelClick}>{t('common-ui:cancel.action', 'Cancel')} </InlineButton>
}
