import React from 'react'
import { InlineButton } from '@fs/zion-ui'
import { useTranslation } from 'react-i18next'
import {
  useChatMultiSelectDispatch,
  useChatMultiSelectState,
  actionTypes,
} from '../../../providers/ChatMultiSelectProvider'

export default function ChatMultiSelectClearButton() {
  const [t] = useTranslation()
  const chatMultiSelectDispatch = useChatMultiSelectDispatch()
  const { selectedChannels } = useChatMultiSelectState()

  const handleClearSelection = () => {
    chatMultiSelectDispatch({
      type: actionTypes.CLEAR_SELECTED_CHANNELS,
    })
  }

  const hasSelectedChannels = selectedChannels.size > 0

  return hasSelectedChannels ? (
    <InlineButton onClick={handleClearSelection}>{t('chat.multi-select-buttons.clear', 'Clear')}</InlineButton>
  ) : null
}
