import { Toggle } from '@fs/zion-ui'
import React from 'react'
import { useTranslation } from 'react-i18next'
import { CHAT_ACTIONS } from '../hooks/useChatReducer'
import { CHAT_PREF, setChatPreference } from '../services/chatUserPreferenceService/chatUserPreferenceService'
import { LOG_LEVEL } from '../global/chatLog'
import { useChatDispatch, useChatState } from '../providers/ChatStateProvider'
import useChatLog from '../hooks/useChatLog'

const ToggleShowEvents = () => {
  const [t] = useTranslation()
  const { log, track } = useChatLog({ component: '[ToggleShowEvents]' })
  const chatDispatch = useChatDispatch()
  const { showEvents } = useChatState()

  const toggleShowEvents = async ({ target }) => {
    try {
      const newShowEvents = target.checked
      chatDispatch({
        type: CHAT_ACTIONS.SHOW_EVENTS,
        showEvents: newShowEvents,
      })
      await setChatPreference(CHAT_PREF.SHOW_EVENT_CHATS, newShowEvents)
      track({ link_name: `Chat:Turn Show Event Chats ${newShowEvents ? 'on' : 'off'}` })
    } catch (err) {
      log({ msg: `setPreference (${CHAT_PREF.SHOW_EVENT_CHATS}) failed! - ${err}`, level: LOG_LEVEL.ERROR })
    }
  }

  return (
    <Toggle
      data-testid="show-event-chats"
      label={t('chat.show-event-chats.label', 'Show event chats')}
      name="showEventsToggle"
      checked={showEvents}
      onChange={toggleShowEvents}
      allowLabelWrapping
    />
  )
}

export default ToggleShowEvents
