import React from 'react'
import { Row, Paragraph } from '@fs/zion-ui'
import { ControlHide, MenuClose, SocialEmailOpen, Notice, NoticeMute } from '@fs/zion-icon'
import { i18n } from '@fs/zion-locale'
import { CHAT_PREF } from '../../services/chatUserPreferenceService/chatUserPreferenceService'
import ChatMultiSelectCancelButton from './ChatMultiSelectButtons/ChatMultiSelectCancelButton'
import ChatMultiSelectClearButton from './ChatMultiSelectButtons/ChatMultiSelectClearButton'
import ChatMultiSelectOption from './ChatMultiSelectOption'
import { useMultiSelectActions } from '../../hooks/useMultiSelectActions'
import { useChatMultiSelectState } from '../../providers/ChatMultiSelectProvider'

const OVERLAY_STRINGS = {
  hide: {
    title: i18n.t('chat.multi-select-buttons.hide', 'Hide Selected Chats'),
    message: i18n.t(
      'chat.multi-select-buttons.hide-dialog',
      'You can view hidden chats later from the three-dot menu at top right.'
    ),
  },
  leave: {
    title: i18n.t('chat.multi-select-buttons.leave', 'Leave Selected Chats'),
    message: (
      <>
        <Paragraph size="sm">
          {i18n.t(
            'chat.multi-select-buttons.leave-dialog-1',
            'To rejoin a Public Group later, search for it and click to rejoin.'
          )}
        </Paragraph>
        <Paragraph size="sm">
          {i18n.t(
            'chat.multi-select-buttons.leave-dialog-2',
            'You cannot leave a FamilySearch Group from Chat. You must do it under [username] > Family Groups from the main page.'
          )}
        </Paragraph>
      </>
    ),
  },
  markAsRead: {
    title: i18n.t('chat.multi-select-buttons.mark-read', 'Mark Selected Chats as Read'),
    message: '',
  },
  mute: {
    title: i18n.t('chat.multi-select-buttons.mute', 'Mute Selected Chats'),
    message: i18n.t(
      'chat.multi-select-buttons.mute-dialog',
      'This will turn the chime off for just the selected chats.'
    ),
  },
  unmute: {
    title: i18n.t('chat.multi-select-buttons.unmute', 'Unmute Selected Chats'),
    message: i18n.t(
      'chat.multi-select-buttons.unmute-dialog',
      'This will turn the chime on for just the selected chats.'
    ),
  },
}

export default function ChatMultiSelectOptions() {
  const {
    hideSelectedChannels,
    leaveSelectedChannels,
    markSelectedChannelsAsRead,
    muteSelectedChannels,
    unmuteSelectedChannels,
    canLeaveAllSelectedChannels,
  } = useMultiSelectActions()
  const { selectedChannels } = useChatMultiSelectState()

  // Enable all actions if at least one channel is selected
  const hasSelectedChannels = selectedChannels.size > 0

  return (
    <Row alignY="middle" alignX="end" wrap>
      <Row>
        <ChatMultiSelectOption
          icon={ControlHide}
          titleName={OVERLAY_STRINGS.hide.title}
          overlayMessage={OVERLAY_STRINGS.hide.message}
          action={hideSelectedChannels}
          disabled={!hasSelectedChannels}
          preferenceKey={CHAT_PREF.HIDE_CONFIRMATION_SHOWN}
        />
        <ChatMultiSelectOption
          icon={MenuClose}
          titleName={OVERLAY_STRINGS.leave.title}
          overlayMessage={OVERLAY_STRINGS.leave.message}
          action={leaveSelectedChannels}
          disabled={!hasSelectedChannels || !canLeaveAllSelectedChannels()}
        />
        <ChatMultiSelectOption
          icon={SocialEmailOpen}
          titleName={OVERLAY_STRINGS.markAsRead.title}
          overlayMessage={OVERLAY_STRINGS.markAsRead.message}
          action={markSelectedChannelsAsRead}
          disabled={!hasSelectedChannels}
        />
        <ChatMultiSelectOption
          icon={NoticeMute}
          titleName={OVERLAY_STRINGS.mute.title}
          overlayMessage={OVERLAY_STRINGS.mute.message}
          action={muteSelectedChannels}
          disabled={!hasSelectedChannels}
          preferenceKey={CHAT_PREF.MUTE_CONFIRMATION_SHOWN}
        />
        <ChatMultiSelectOption
          icon={Notice}
          titleName={OVERLAY_STRINGS.unmute.title}
          overlayMessage={OVERLAY_STRINGS.unmute.message}
          action={unmuteSelectedChannels}
          disabled={!hasSelectedChannels}
          preferenceKey={CHAT_PREF.UNMUTE_CONFIRMATION_SHOWN}
        />
      </Row>
      <Row alignY="middle" gutters="xxs">
        <ChatMultiSelectCancelButton />
        <ChatMultiSelectClearButton />
      </Row>
    </Row>
  )
}
