import React from 'react'
import { IconButton, useOverlay } from '@fs/zion-ui'
import { getChatPreference } from '../../services/chatUserPreferenceService/chatUserPreferenceService'

import ChatMultiSelectDialogOverlay from './ChatMultiSelectDialogOverlay'

export default function ChatMultiSelectOption({
  icon,
  titleName,
  overlayMessage,
  action,
  disabled = false,
  preferenceKey,
}) {
  const overlay = useOverlay()

  const handleClick = async () => {
    // If there's no message, execute the action directly without showing overlay
    if (overlayMessage === '') {
      if (action) {
        try {
          await action()
        } catch (error) {
          console.error('Error executing action:', error)
        }
      }
      return
    }

    // Check if we should skip the confirmation overlay based on user preference
    if (preferenceKey) {
      try {
        const confirmationShown = await getChatPreference(preferenceKey)
        if (confirmationShown) {
          // User has already seen this confirmation, execute action directly
          if (action) {
            action()
          }
          return
        }
      } catch (error) {
        // If preference check fails, show the overlay as fallback
        // Silently continue to show overlay on error
      }
    }

    // Show overlay for confirmation
    overlay.handleClick()
  }

  return (
    <>
      <IconButton dense Icon={icon} title={titleName} onClick={handleClick} disabled={disabled} />
      <ChatMultiSelectDialogOverlay
        overlay={overlay}
        titleName={titleName}
        message={overlayMessage}
        action={action}
        preferenceKey={preferenceKey}
      />
    </>
  )
}
