import React from 'react'
import { MarginBox, Row } from '@fs/zion-ui'
import ToggleShowEvents from './ToggleShowEvents'
import { useChatState } from '../providers/ChatStateProvider'
import ChatMultiSelectButton from './ChatMultiSelect/ChatMultiSelectButtons/ChatMultiSelectButton'
import ChatMultiSelectOptions from './ChatMultiSelect/ChatMultiSelectOptions'
import { useChatMultiSelectState } from '../providers/ChatMultiSelectProvider'
import useChatFlags from '../hooks/useChatFlags'

const ChatOptions = () => {
  const { restrictToManagedGroups } = useChatState()
  const { multiSelectIsActive } = useChatMultiSelectState()
  const { messagingChatMultiselectChannelsIsOn, messagingChatLeftPanelRedesignIsOn } = useChatFlags()
  const showEventsToggle = !restrictToManagedGroups && !messagingChatLeftPanelRedesignIsOn

  return (
    <MarginBox
      marginX={messagingChatLeftPanelRedesignIsOn ? 'xxs' : 'xs'}
      marginY={messagingChatLeftPanelRedesignIsOn ? 'xxs' : 'xs'}
      data-testid="chat-options"
    >
      {multiSelectIsActive ? (
        <ChatMultiSelectOptions />
      ) : (
        <Row>
          {!messagingChatLeftPanelRedesignIsOn && <div growX>{showEventsToggle && <ToggleShowEvents />}</div>}
          {messagingChatMultiselectChannelsIsOn && <ChatMultiSelectButton />}
        </Row>
      )}
    </MarginBox>
  )
}

export default ChatOptions
